@spec arrange_page_spec  src=tests/specs/arrange_page_spec.lua  loc=743  sha=61aa319  cases=35
@exercises commandManager (h.cmgr), configManager (h.cm), arrangeManager (am)
@surface   cmgr:push, cmgr:invoke, cm:set, am:tracksTakes, cm:get, am:resizeTake
@harness   mk, reaper:setTrackName, reaper:addItem, reaper.SetMediaItemSelected, reaper:setCursor

# Intent
  Pin-tests for arrangePage's Page interface and arrange-scope edit commands.
  Cursor mechanics, off-screen no-op, and selection-precedence: arrange_view_spec.

# Helpers
  @fn newArrangePage(cm, ds, cmgr, chrome, gui)  @ 47-55

# Cases
  @case 'bind / unbind are no-ops — arrange page never re-keys cm'  [harness]  @ 59-69
  @case 'focusState before any render returns both bits false'  [harness]  @ 73-80
  @case 'arrange-scope is registered at module load (cursorRight invokable)'  [harness]  @ 84-91
  @case 'arrange-scope place commands are registered (drop0/dropA/dropZ invokable)'  [harness]  @ 95-106
  @case 'a place-command drop advances the cursor by cm.arrangeAdvanceBy rows'  [harness]  @ 110-133
  @case 'arrangeAdvanceBy0..9 set cm.arrangeAdvanceBy at project tier'  [harness]  @ 137-148
  @case 'chained Super-D walks down — each clone becomes the selection for the next'  [harness]  @ 152-171
  @case 'a place-command drop inherits the length of an existing instance'  [harness]  @ 175-197
  @case 'arrangeNudgeForward moves the cursor take by one row'  [harness]  @ 201-215
  @case 'arrangeNudgeForward moves a take taller than one row'  [harness]  @ 219-234
  @case 'arrangeGrowTake lengthens the cursor take by one row'  [harness]  @ 238-255
  @case 'arrangeGrowTake silently no-ops at the take-source length cap'  [harness]  @ 259-273
  @case 'arrangeShrinkTake reduces the cursor take by one row'  [harness]  @ 277-292
  @case 'arrangeDeleteTake removes the cursor take'  [harness]  @ 296-310
  @case 'arrangeNudgeForward is a no-op when the next row is occupied'  [harness]  @ 314-330
  @case 'arrangeNudgeBack is a no-op when the take is already at row 0'  [harness]  @ 334-348
  @case 'arrangeGrowTake against a flush neighbour stores intent; rendered is gap-capped'  [harness]  @ 352-370
  @case 'arrangeNudgeForward steps past a neighbour without a start-collision'  [harness]  @ 374-394
  @case 'arrangeNudgeForward truncates the displaced take when stepping past'  [harness]  @ 398-420
  @case 'arrangeDive switches to the tracker for the cursor MIDI take'  [harness]  @ 424-439
  @case 'createSlot dives the tracker onto the freshly-minted take'  [harness]  @ 443-458
  @case 'arrangeDive over an audio take still switches and restores (no take pinned)'  [harness]  @ 462-476
  @case 'arrangeDive over empty space switches and restores'  [harness]  @ 480-492
  @case 'kb edit acts on the cursor take when nothing is selected'  [harness]  @ 496-514
  @case 'kb delete no-ops when the cursor sits off every take'  [harness]  @ 518-536
  @case 'kb nudge no-ops when cursor sits on empty space'  [harness]  @ 540-557
  @case 'an edit command is a no-op when the cursor is over empty space'  [harness]  @ 561-576
  @case 'a second delete finds an empty cell under the cursor — no-op'  [harness]  @ 580-598
  @case 'seedCursorFromReaper lands the cursor on the selected take'  [harness]  @ 602-619
  @case 'seedCursorFromReaper falls back to the edit-cursor row'  [harness]  @ 623-637
  @case 'arrangeTakeProperties routes the focused MIDI take through onTakeProperties'  [harness]  @ 646-659
  @case 'arrangeTakeProperties is a no-op on an audio take'  [harness]  @ 663-676
  @case 'arrangeDuplicateBelow drops a pooled clone at the focused take\'s natural end'  [harness]  @ 680-696
  @case 'arrangeDuplicateBelow is silent on start-collision and on audio takes'  [harness]  @ 700-718
  @case 'arrangeDuplicateUnpooledBelow mints a fresh-pool clone and auto-opens take-props'  [harness]  @ 722-740

